import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { AcousticEngine } from '../../aether/src/acoustic-siphon';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

/**
 * Acoustic Listener — Parsing Sound back into Intent
 */

async function main() {
  const wavPath = path.join(__dirname, 'sentence-output.wav');
  if (!fs.existsSync(wavPath)) {
    console.error('Error: sentence-output.wav not found. Run say-sentence.ts first.');
    return;
  }

  console.log('============================================================');
  console.log(' Acoustic Vacuum Siphon — Listening to the Resonance');
  console.log('============================================================\n');

  const engine = new AcousticEngine();
  const buffer = fs.readFileSync(wavPath);
  
  // Basic WAV header skip (44 bytes) to get PCM data
  const pcmData = buffer.slice(44);
  const int16Array = new Int16Array(pcmData.buffer, pcmData.byteOffset, pcmData.byteLength / 2);
  const float32Array = new Float32Array(int16Array.length);
  for (let i = 0; i < int16Array.length; i++) {
    float32Array[i] = int16Array[i] / 32768;
  }

  // Slice into windows (300ms windows match our condensation length)
  const windowSize = Math.floor(24000 * 0.3);
  const numWindows = Math.floor(float32Array.length / windowSize);

  console.log('[LISTEN] Parsing ' + numWindows + ' phonetic units...\n');
  const parsedSequence: string[] = [];

  for (let w = 0; w < numWindows; w++) {
    const start = w * windowSize;
    const end = start + windowSize;
    const chunk = float32Array.slice(start, end);

    const result = await engine.siphon(chunk);
    const vector = result.vector;
    const phonemeId = vector.nodeId.replace('phoneme_', '');
    
    console.log('Window ' + w + ': [' + phonemeId + '] (Trace: ' + vector.boundaryTrace + ') SSD: ' + result.isDraftAccepted);
    if (phonemeId !== 'unrecognized_consensus' && phonemeId !== 'SIL') {
      parsedSequence.push(phonemeId);
    }
  }

  console.log('\n============================================================');
  console.log(' RECONSTRUCTED PHONEMES:');
  console.log(' ' + parsedSequence.join(' '));
  console.log('============================================================');
}

main().catch(console.error);